                if part.startswith(subject):
                    # Remove subject and add relative clause marker
                    remainder = part[len(subject):].lstrip()
                    if remainder.startswith(" is "):
                        part = "which" + remainder
                    elif remainder.startswith("'s"):
                        part = "whose" + remainder
                    else:
                        part = "which " + remainder

            sentence_parts.append(part)

        # Join with appropriate connectors
        if len(sentence_parts) == 1:
            sentence = sentence_parts[0] + "."
        elif len(sentence_parts) == 2:
            sentence = sentence_parts[0] + ", and " + sentence_parts[1] + "."
        else:
            # Create better flow with commas and relative clauses
            sentence = ", ".join(sentence_parts[:-1]) + ", and " + sentence_parts[-1] + "."

    # Ensure the first character is capitalised
    sentence = sentence[0].upper() + sentence[1:]
    return sentence

